configuration.jsScript:
// *** OPERATOR: set PVLIB_HEALTH_URL to your pvlib-service /health endpoint ***
var PVLIB_HEALTH_URL = 'http://pvlib-service:8000/health';
metadata['pvlibHealthUrl'] = PVLIB_HEALTH_URL;
return { msg: msg, metadata: metadata, msgType: msgType };

// Returns 'stalled' when HTTP error OR status != 'ok'; otherwise 'ok'.
var httpStatus = parseInt(metadata['status'] || '0', 10);
if (httpStatus >= 500 || httpStatus === 0) { return ['stalled']; }
try {
  var body = (typeof msg === 'string') ? JSON.parse(msg) : msg;
  if (body && body.status === 'ok') { return ['ok']; }
  return ['stalled'];
} catch(e) { return ['stalled']; }

configuration.alarmDetailsBuildJs:
var details = {};
try {
  var body = (typeof msg === 'string') ? JSON.parse(msg) : msg;
  details.status = body.status;
  details.last_cycle_finished_at = body.last_cycle_finished_at;
  details.stale_seconds = body.stale_seconds;
  details.last_cycle_failures = body.last_cycle_failures;
} catch(e) { details.raw = String(msg); }
return details;
